from sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelfrom typing import Optionalfrom sqlalchemy import TIMESTAMP,BOOLEAN,ARRAY,VARCHAR,NUMERIC,TEXT,UUIDimport uuid,decimal,datetimefrom sqlalchemy.dialects.postgresql import JSONBclass PlatformMatchResultModel(BaseModel):    __tablename__ = 'platform_match_result'    id: Mapped[uuid.UUID] = mapped_column(UUID, primary_key=True)    seeker_id: Mapped[uuid.UUID] = mapped_column(UUID, comment="""发起匹配的人""")    candidate_id: Mapped[uuid.UUID] = mapped_column(UUID, comment="""候选人""")    need_id: Mapped[Optional[uuid.UUID]] = mapped_column(UUID)    score_total: Mapped[decimal.Decimal] = mapped_column(NUMERIC, comment="""综合评分 0-100""")    score_detail: Mapped[Optional[dict]] = mapped_column(JSONB, comment="""{"skill":97,"industry":92,"role":95,...}""")    reasons: Mapped[Optional[list]] = mapped_column(ARRAY(TEXT), comment="""AI生成的推荐理由（3-5条）""")    algo_version: Mapped[Optional[str]] = mapped_column(VARCHAR(10), comment="""算法版本，便于A/B测试""")    computed_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP)    is_featured: Mapped[Optional[bool]] = mapped_column(BOOLEAN)    match_resource: Mapped[Optional[str]] = mapped_column(VARCHAR(10), comment="""cofounder_need/user_profile""")